alue="maison_individuelle">Maison individuelle</option></select></div><div class="fr-input-group"><label class="fr-label mb-2" for="_R_3fh97d6_">Espaces extérieurs disponibles</label><button type="button" role="combobox" aria-controls="radix-_R_1ffh97d6_" aria-expanded="false" aria-autocomplete="none" dir="ltr" data-state="closed" data-placeholder="" class="fr-select w-full"><span class="block truncate whitespace-nowrap overflow-hidden text-left"><span style="pointer-events:none"><span class="block truncate whitespace-nowrap overflow-hidden">Sélectionner vos espaces disponibles</span></span></span></button><select aria-hidden="true" tabindex="-1" style="position:absolute;border:0;width:1px;height:1px;padding:0;margin:-1px;overflow:hidden;clip:rect(0, 0, 0, 0);white-space:nowrap;word-wrap:normal"></select></div></div><div class="mt-5 flex flex-col items-stretch gap-3 md:flex-row md:items-center md:justify-end"><span class="w-full text-center md:w-auto md:text-left">Un <strong>service public</strong> gratuit, fiable et neutre</span><button id="fr-button-_R_2nh97d6_" class="fr-btn fr-icon-arrow-right-line fr-btn--icon-right Button__StyledButton-sc-8dcb086a-0 eKftSe w-full md:w-auto md:flex-none md:flex md:justify-center" type="button" disabled="" variant="default">Comparer les solutions</button></div></form></div></div></div><div class="fr-container fr-py-6w"><h3 class="fr-h6 fr-mb-3v font-medium uppercase">Pourquoi choisir un chauffage écologique ?</h3><p class="fr-h2 font-bold">Des arguments concrets, bien au-delà de l’environnement</p><div class="fr-grid-row fr-grid-row--gutters fr-mt-4w"><div class="fr-col-12 fr-col-md-4"><div class="w-full overflow-hidden rounded-lg border-2 border-[#DDDDDD] bg-[#FEFCFA] p-6 h-full"><h5 class="fr-h4"><img alt="" loading="lazy" width="24" height="24" decoding="async" data-nimg="1" class="inline-block mr-3 mb-1" style="color:transparent" srcSet="/_next/image?url=%2Ficons%2Ficon-money.png&amp;w=32&amp;q=75 1x, /_next/image?url=%2Ficons%2Ficon-money.png&amp;w=48&amp;q=75 2x" src="/_next/image?url=%2Ficons%2Ficon-money.png&amp;w=48&amp;q=75"/>Protégez-vous des hausses du gaz ou du fioul</h5><p>Prix du gaz et fioul : instables. Énergies renouvelables locales : stables sur le long terme.</p></div></div><div class="fr-col-12 fr-col-md-4"><div class="w-full overflow-hidden rounded-lg border-2 border-[#DDDDDD] bg-[#FEFCFA] p-6 h-full"><h5 class="fr-h4"><img alt="" loading="lazy" width="24" height="24" decoding="async" data-nimg="1" class="inline-block mr-3 mb-1" style="color:transparent" srcSet="/_next/image?url=%2Ficons%2Ficon-immeuble.png&amp;w=32&amp;q=75 1x, /_next/image?url=%2Ficons%2Ficon-immeuble.png&amp;w=48&amp;q=75 2x" src="/_next/image?url=%2Ficons%2Ficon-immeuble.png&amp;w=48&amp;q=75"/>Bénéficiez d’aides pour financer votre projet</h5><p>MaPrimeRénov&#x27;, CEE, aides locales : des financements publics couvrant une grande partie des travaux.</p></div></div><div class="fr-col-12 fr-col-md-4"><div class="w-full overflow-hidden rounded-lg border-2 border-[#DDDDDD] bg-[#FEFCFA] p-6 h-full"><h5 class="fr-h4"><img alt="" loading="lazy" width="24" height="24" decoding="async" data-nimg="1" class="inline-block mr-3 mb-1" style="color:transparent" srcSet="/_next/image?url=%2Ficons%2Ficon-graph.png&amp;w=32&amp;q=75 1x, /_next/image?url=%2Ficons%2Ficon-graph.png&amp;w=48&amp;q=75 2x" src="/_next/image?url=%2Ficons%2Ficon-graph.png&amp;w=48&amp;q=75"/>Améliorez l&#x27;étiquette DPE de votre bien</h5><p>Une meilleure classe DPE protège votre bien immobilier des décotes et le maintient compétitif sur le marché.</p></div></div><div class="fr-col-12 fr-col-md-4"><div class="w-full overflow-hidden rounded-lg border-2 border-[#DDDDDD] bg-[#FEFCFA] p-6 h-full"><h5 class="fr-h4"><img alt="" loading="lazy" width="24" height="24" decoding="async" data-nimg="1" class="inline-block mr-3 mb-1" style="color:transparent" srcSet="/_next/image?url=%2Ficons%2Ficon-feuille.png&amp;w=32&amp;q=75 1x, /_next/image?url=%2Ficons%2Ficon-feuille.png&amp;w=48&amp;q=75 2x" src="/_next/image?url=%2Ficons%2Ficon-feuille.png&amp;w=48&amp;q=75"/>Réduisez vos émissions de CO2</h5><p>Passer à un système de chauffage écologique peut diviser par deux les émissions de votre chauffage : un geste concret pour la transition écologique.</p></div></div><div class="fr-col-12 fr-col-md-4"><div class="w-full overflow-hidden rounded-lg border-2 border-[#DDDDDD] bg-[#FEFCFA] p-6 h-full"><h5 class="fr-h4"><img alt="" loading="lazy" width="24" height="24" decoding="async" data-nimg="1" class="inline-block mr-3 mb-1" style="color:transparent" srcSet="/_next/image?url=%2Ficons%2Ficon-thermometre.png&amp;w=32&amp;q=75 1x, /_next/image?url=%2Ficons%2Ficon-thermometre.png&amp;w=48&amp;q=75 2x" src="/_next/image?url=%2Ficons%2Ficon-thermometre.png&amp;w=48&amp;q=75"/>Gagnez en confort toute l’année</h5><p>Chaleur homogène en hiver, fraîcheur possible en été avec certaines solutions réversibles.</p></div></div><div class="fr-col-12 fr-col-md-4"><div class="w-full overflow-hidden rounded-lg border-2 border-[#DDDDDD] bg-[#FEFCFA] p-6 h-full"><h5 class="fr-h4"><img alt="" loading="lazy" width="24" height="24" decoding="async" data-nimg="1" class="inline-block mr-3 mb-1" style="color:transparent" srcSet="/_next/image?url=%2Ficons%2Ficon-money.png&amp;w=32&amp;q=75 1x, /_next/image?url=%2Ficons%2Ficon-money.png&amp;w=48&amp;q=75 2x" src="/_next/image?url=%2Ficons%2Ficon-money.png&amp;w=48&amp;q=75"/>Réduisez vos factures d’énergie</h5><p>Les systèmes de chauffage écologiques sont souvent moins chers et plus efficaces que le gaz ou le fioul.</p></div></div></div></div><div class="bg-[#F3F6FE]"><div class="fr-container fr-py-6w"><h3 class="fr-h6 fr-mb-3v font-medium uppercase">Ressources Pédagogiques</h3><p class="fr-h2 font-bold">Tout comprendre avant de se lancer</p><div class="fr-mt-4w flex items-center gap-2 md:gap-4"><button id="fr-button-_R_1q97d6_" class="fr-btn fr-btn--secondary fr-icon-arrow-left-s-line Button__S